namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Name { get; set; } = "";
    public string Description { get; set; } = "";
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Bio { get; set; } = "";
    public string Email { get; set; } = "";
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Semester { get; set; } = "";
    public bool IsFeatured { get; set; }
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CourseCatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CourseCatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and language." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and their significance." }
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and leads the university's AI research lab.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor of Computer Science", Bio = "Dr. Miller focuses on software engineering and distributed systems. He spent 10 years in industry before joining academia.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Dr. Elena Rodriguez", Title = "Professor of Mathematics", Bio = "Dr. Rodriguez is an expert in abstract algebra and number theory with numerous international awards.", Email = "e.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Thompson", Title = "Associate Professor of English", Bio = "Dr. Thompson specializes in 19th-century American literature and creative writing.", Email = "m.thompson@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Park", Title = "Professor of Physics", Bio = "Dr. Park researches quantum mechanics and particle physics. She previously worked at CERN.", Email = "l.park@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Wilson", Title = "Associate Professor of History", Bio = "Dr. Wilson focuses on modern European history and the history of technology.", Email = "r.wilson@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Semester = "Fall 2026", IsFeatured = true, DepartmentId = 1, Department = _departments[0], Instructor = instructors[0] },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:00–11:20 AM", Semester = "Fall 2026", IsFeatured = true, DepartmentId = 1, Department = _departments[0], Instructor = instructors[1] },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Introduction to database design, SQL, normalization, transaction processing, and modern database technologies.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 1, Department = _departments[0], Instructor = instructors[1] },
            new() { Id = 4, Code = "CS 450", Title = "Machine Learning", Description = "Foundations of machine learning including supervised and unsupervised learning, neural networks, and practical applications.", Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", Semester = "Fall 2026", IsFeatured = true, DepartmentId = 1, Department = _departments[0], Instructor = instructors[0] },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 2, Department = _departments[1], Instructor = instructors[2] },
            new() { Id = 6, Code = "MATH 220", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to computer science and engineering.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Semester = "Fall 2026", IsFeatured = true, DepartmentId = 2, Department = _departments[1], Instructor = instructors[2] },
            new() { Id = 7, Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading, thinking, and writing skills through essay composition and peer review.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 3, Department = _departments[2], Instructor = instructors[3] },
            new() { Id = 8, Code = "ENG 250", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, examining major authors and literary movements.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 3, Department = _departments[2], Instructor = instructors[3] },
            new() { Id = 9, Code = "PHYS 201", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach for science and engineering majors.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 4, Department = _departments[3], Instructor = instructors[4] },
            new() { Id = 10, Code = "PHYS 350", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave functions, the Schrödinger equation, and applications to atomic systems.", Credits = 4, Schedule = "Tue/Thu 11:00 AM–12:20 PM", Semester = "Fall 2026", IsFeatured = true, DepartmentId = 4, Department = _departments[3], Instructor = instructors[4] },
            new() { Id = 11, Code = "HIST 101", Title = "World History I", Description = "Survey of world civilizations from ancient times to 1500 CE, exploring cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 5, Department = _departments[4], Instructor = instructors[5] },
            new() { Id = 12, Code = "HIST 320", Title = "History of Technology", Description = "Explores how technological innovations have shaped societies from the Industrial Revolution to the digital age.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Semester = "Fall 2026", IsFeatured = false, DepartmentId = 5, Department = _departments[4], Instructor = instructors[5] }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

