.page {
    display: flex;
    flex-direction: column;
    min-height: 100vh;
}

.top-bar {
    background-color: #1a237e;
    color: white;
    padding: 0.75rem 1.5rem;
    position: sticky;
    top: 0;
    z-index: 100;
}

.top-bar-inner {
    max-width: 1200px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.top-bar .brand {
    font-size: 1.25rem;
    font-weight: bold;
    color: white;
    text-decoration: none;
}

.top-bar nav a {
    color: #e8eaf6;
    text-decoration: none;
    margin-left: 1.5rem;
    font-weight: 500;
}

.top-bar nav a:hover {
    color: white;
    text-decoration: underline;
}

.content-area {
    flex: 1;
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem 1.5rem;
    width: 100%;
}

.site-footer {
    background-color: #f5f5f5;
    text-align: center;
    padding: 1rem;
    border-top: 1px solid #e0e0e0;
    color: #666;
    font-size: 0.875rem;
}

@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CourseCatalogService CatalogService

<PageTitle>Home — University Course Catalog</PageTitle>

<section class="hero">
    <h1>Welcome to the Course Catalog</h1>
    <p>Browse our Fall 2026 courses, explore departments, and submit your enrollment request.</p>
    <a class="btn-primary" href="/courses">Browse All Courses</a>
</section>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="badge">@course.Code</span>
                <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                <p>@course.Department.Name &bull; @course.Credits credits</p>
                <p class="schedule">@course.Schedule</p>
            </div>
        }
    </div>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="dept-grid">
        @foreach (var dept in departments)
        {
            <a class="dept-card" href="/courses?departmentId=@dept.Id">
                <h3>@dept.Name</h3>
                <p>@dept.Description</p>
            </a>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

