arguments.file_text:
@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CourseCatalogService CatalogService

<PageTitle>Courses — University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search courses..." class="search-input" />
    <select name="departmentId" class="dept-select">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-search">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <p class="result-count">Showing @courses.Count course(s)</p>
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-info">
                    <span class="code">@course.Code</span>
                    <a href="/courses/@course.Id" class="title">@course.Title</a>
                    <span class="dept">@course.Department.Name</span>
                </div>
                <div class="course-meta">
                    <span class="credits">@course.Credits cr</span>
                    <span class="schedule">@course.Schedule</span>
                </div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

::deep .filter-bar {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

::deep .search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .dept-select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
    min-width: 160px;
}

::deep .btn-search {
    background: #1a237e;
    color: white;
    border: none;
    padding: 0.5rem 1.25rem;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 600;
}

::deep .btn-search:hover {
    background: #283593;
}

::deep .no-results {
    padding: 2rem;
    text-align: center;
    color: #666;
    font-style: italic;
}

::deep .result-count {
    color: #666;
    font-size: 0.9rem;
    margin-bottom: 1rem;
}

::deep .course-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

::deep .course-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    background: white;
    flex-wrap: wrap;
    gap: 0.5rem;
}

::deep .course-row:hover {
    border-color: #1a237e;
    box-shadow: 0 1px 4px rgba(0,0,0,0.06);
}

::deep .course-info {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
}

::deep .course-info .code {
    background: #e8eaf6;
    color: #1a237e;
    font-weight: 600;
    font-size: 0.8rem;
    padding: 0.2rem 0.5rem;
    border-radius: 3px;
}

::deep .course-info .title {
    color: #1a237e;
    font-weight: 600;
    text-decoration: none;
}

::deep .course-info .title:hover {
    text-decoration: underline;
}

::deep .course-info .dept {
    color: #888;
    font-size: 0.85rem;
}

::deep .course-meta {
    display: flex;
    gap: 1rem;
    font-size: 0.85rem;
    color: #666;
}

::deep .breadcrumb {
    font-size: 0.9rem;
    margin-bottom: 1rem;
    color: #666;
}

::deep .breadcrumb a {
    color: #1a237e;
    text-decoration: none;
}

::deep .breadcrumb a:hover {
    text-decoration: underline;
}

::deep .detail-header {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

::deep .detail-header h1 {
    margin: 0;
}

::deep .code-badge {
    background: #1a237e;
    color: white;
    padding: 0.3rem 0.75rem;
    border-radius: 4px;
    font-weight: 600;
    font-size: 0.9rem;
}

::deep .detail-grid {
    display: grid;
    grid-template-columns: 1fr 300px;
    gap: 2rem;
    align-items: start;
}

@media (max-width: 768px) {
    ::deep .detail-grid {
        grid-template-columns: 1fr;
    }
}

::deep .detail-main h2 {
    color: #1a237e;
    margin-top: 1.5rem;
    margin-bottom: 0.5rem;
}

::deep .detail-main h2:first-child {
    margin-top: 0;
}

::deep .instructor-card {
    background: #f9f9f9;
    padding: 1.25rem;
    border-radius: 8px;
    border: 1px solid #e0e0e0;
}

::deep .instructor-card h3 {
    margin: 0 0 0.25rem;
    color: #333;
}

::deep .instructor-card .instructor-title {
    color: #1a237e;
    font-weight: 500;
    margin-bottom: 0.75rem;
}

::deep .instructor-card .instructor-email {
    margin-top: 0.75rem;
    color: #555;
}

::deep .info-box {
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
}

::deep .info-box h3 {
    margin: 0 0 1rem;
    color: #1a237e;
}

::deep .info-box dl {
    margin: 0;
}

::deep .info-box dt {
    font-weight: 600;
    font-size: 0.85rem;
    color: #666;
    margin-top: 0.75rem;
}

::deep .info-box dt:first-child {
    margin-top: 0;
}

::deep .info-box dd {
    margin: 0.2rem 0 0;
    font-size: 0.95rem;
}

::deep .btn-enroll {
    display: block;
    text-align: center;
    margin-top: 1.5rem;
    background: #1a237e;
    color: white;
    padding: 0.75rem;
    border-radius: 4px;
    text-decoration: none;
    font-weight: 600;
}

::deep .btn-enroll:hover {
    background: #283593;
}

