arguments.file_text:
@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CourseCatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1>Submit Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>✓ Request Submitted</h2>
        <p>Your enrollment request has been received. You will be notified by email once it is processed.</p>
        <a href="/courses">← Browse More Courses</a>
    </div>
}
else
{
    <p class="form-intro">Fill out the form below to request enrollment in a course. All fields are required.</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="error-message">@errorMessage</div>
    }

    <form method="post" class="enroll-form" @formname="enrollment">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g., STU-12345" />
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="">— Select a course —</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code — @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn-submit">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string? errorMessage;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? ""))
        {
            if (string.IsNullOrWhiteSpace(Model.StudentName) ||
                string.IsNullOrWhiteSpace(Model.StudentId) ||
                Model.CourseId == 0)
            {
                errorMessage = "Please fill in all required fields.";
                return;
            }

            if (CatalogService.SubmitEnrollmentRequest(Model))
            {
                submitted = true;
            }
            else
            {
                errorMessage = "Unable to process your request. Please verify your information and try again.";
            }
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }
}

::deep .form-intro {
    color: #555;
    margin-bottom: 1.5rem;
}

::deep .enroll-form {
    max-width: 500px;
}

::deep .form-group {
    margin-bottom: 1.25rem;
}

::deep .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.3rem;
    color: #333;
}

::deep .form-group input,
::deep .form-group select {
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .form-group input:focus,
::deep .form-group select:focus {
    outline: none;
    border-color: #1a237e;
    box-shadow: 0 0 0 2px rgba(26, 35, 126, 0.1);
}

::deep .btn-submit {
    background: #1a237e;
    color: white;
    border: none;
    padding: 0.75rem 1.5rem;
    border-radius: 4px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
}

::deep .btn-submit:hover {
    background: #283593;
}

::deep .success-message {
    background: #e8f5e9;
    border: 1px solid #a5d6a7;
    border-radius: 8px;
    padding: 2rem;
    max-width: 500px;
}

::deep .success-message h2 {
    color: #2e7d32;
    margin: 0 0 0.5rem;
}

::deep .success-message a {
    color: #1a237e;
    text-decoration: none;
    display: inline-block;
    margin-top: 1rem;
}

::deep .success-message a:hover {
    text-decoration: underline;
}

::deep .error-message {
    background: #fce4ec;
    border: 1px solid #ef9a9a;
    color: #c62828;
    padding: 0.75rem 1rem;
    border-radius: 4px;
    margin-bottom: 1.25rem;
    max-width: 500px;
}

