toolArgs.file_text:
::deep .form-intro {
    color: #555;
    margin-bottom: 1.5rem;
}

::deep .enroll-form {
    max-width: 500px;
}

::deep .form-group {
    margin-bottom: 1.25rem;
}

::deep .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.3rem;
    color: #333;
}

::deep .form-group input,
::deep .form-group select {
    width: 100%;
    padding: 0.6rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .form-group input:focus,
::deep .form-group select:focus {
    outline: none;
    border-color: #1a237e;
    box-shadow: 0 0 0 2px rgba(26, 35, 126, 0.1);
}

::deep .btn-submit {
    background: #1a237e;
    color: white;
    border: none;
    padding: 0.75rem 1.5rem;
    border-radius: 4px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
}

::deep .btn-submit:hover {
    background: #283593;
}

::deep .success-message {
    background: #e8f5e9;
    border: 1px solid #a5d6a7;
    border-radius: 8px;
    padding: 2rem;
    max-width: 500px;
}

::deep .success-message h2 {
    color: #2e7d32;
    margin: 0 0 0.5rem;
}

::deep .success-message a {
    color: #1a237e;
    text-decoration: none;
    display: inline-block;
    margin-top: 1rem;
}

::deep .success-message a:hover {
    text-decoration: underline;
}

::deep .error-message {
    background: #fce4ec;
    border: 1px solid #ef9a9a;
    color: #c62828;
    padding: 0.75rem 1rem;
    border-radius: 4px;
    margin-bottom: 1.25rem;
    max-width: 500px;
}

