    private List<Course> courses = new();
    private bool submitted;
    private string? errorMessage;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.StudentName) ||
            string.IsNullOrWhiteSpace(Model.StudentId) ||
            Model.CourseId == 0)
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        if (CatalogService.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
        }
        else
        {
            errorMessage = "Unable to process your request. Please verify your information and try again.";
        }
    }
}

